import{bQ as a,aL as s,u as n,G as l}from"./chunks/framework.D-yUR65U.js";const e=JSON.parse('{"title":"龙虾养殖 · 004 - OpenClaw 老板模式详解","description":"","frontmatter":{"title":"龙虾养殖 · 004 - OpenClaw 老板模式详解","date":"2026-04-19T00:00:00.000Z","tags":["OpenClaw"],"categories":["龙虾养殖"],"cover":"/images/cover-lobster-004.png","head":[["link",{"rel":"canonical","href":"https://clawblog.rseg.club/posts/2026/lobster-004"}]]},"headers":[],"relativePath":"posts/2026/lobster-004.md","filePath":"posts/2026/lobster-004.md","lastUpdated":null}');const t=a({name:"posts/2026/lobster-004.md"},[["render",function(a,e,t,r,i,o){return s(),n("div",null,[...e[0]||(e[0]=[l('<h1 id="openclaw-老板模式详解" tabindex="-1">OpenClaw 老板模式详解 <a class="header-anchor" href="#openclaw-老板模式详解" aria-label="Permalink to &quot;OpenClaw 老板模式详解&quot;">​</a></h1><h2 id="什么是老板模式" tabindex="-1">什么是老板模式 <a class="header-anchor" href="#什么是老板模式" aria-label="Permalink to &quot;什么是老板模式&quot;">​</a></h2><p>老板模式是 OpenClaw 针对复杂问题设计的一套<strong>三级分工体系</strong>。当一个问题足够复杂、需要多步操作时，系统会自动启用这套架构来提高处理效率和质量。</p><h3 id="三种角色" tabindex="-1">三种角色 <a class="header-anchor" href="#三种角色" aria-label="Permalink to &quot;三种角色&quot;">​</a></h3><div class="table-container"><table><thead><tr><th>角色</th><th>说明</th></tr></thead><tbody><tr><td><strong>老板</strong>（你/Gedr）</td><td>接收问题、分配任务、审查结果、决定是否发回重做、最终回复用户</td></tr><tr><td><strong>经理</strong>（subagent）</td><td>审查员工输出质量，给出&quot;通过/打回重做&quot;的意见，并附上原因</td></tr><tr><td><strong>员工</strong>（subagent）</td><td>执行具体任务（搜索、查文件、写代码等）</td></tr></tbody></table></div><p>简单说：老板动嘴、经理动脑、员工动手。</p><h2 id="什么时候触发老板模式" tabindex="-1">什么时候触发老板模式 <a class="header-anchor" href="#什么时候触发老板模式" aria-label="Permalink to &quot;什么时候触发老板模式&quot;">​</a></h2><p>不是所有问题都需要动用这套体系。根据问题的复杂度，灵活选择：</p><ul><li><strong>直接做</strong>：简单问题（≤3步）直接处理，不需要派员工</li><li><strong>派员工</strong>：需要网络搜索、需要多步操作（&gt;3步）</li><li><strong>派员工 + 经理审查</strong>：需要调研整理报告，输出质量需要把关</li></ul><h2 id="员工复用规则" tabindex="-1">员工复用规则 <a class="header-anchor" href="#员工复用规则" aria-label="Permalink to &quot;员工复用规则&quot;">​</a></h2><p>老板很懂得节约资源：</p><ol><li>旧员工没被占用 → <strong>继续用</strong></li><li>旧员工被占用了 → <strong>spawn 新的</strong></li><li>判断占用：看 subagent 列表里有没有 <code>idle</code> 状态的</li></ol><p>所以每次派任务前，先瞄一眼还有没有闲着的员工，没有就新建一个。</p><h2 id="老板模式的工作流程" tabindex="-1">老板模式的工作流程 <a class="header-anchor" href="#老板模式的工作流程" aria-label="Permalink to &quot;老板模式的工作流程&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户提问 → 老板接收 → 判断复杂度</span></span>\n<span class="line"><span>                      ↓</span></span>\n<span class="line"><span>         ┌─ 简单问题 ─→ 直接处理 → 回复用户</span></span>\n<span class="line"><span>         │</span></span>\n<span class="line"><span>         └─ 复杂问题 ─→ 派员工执行任务</span></span>\n<span class="line"><span>                            ↓</span></span>\n<span class="line"><span>                      经理审查质量</span></span>\n<span class="line"><span>                            ↓</span></span>\n<span class="line"><span>                   ┌─ 通过 → 整合结果 → 回复用户</span></span>\n<span class="line"><span>                   │</span></span>\n<span class="line"><span>                   └─ 打回 → 重新派员工 → 循环直到通过</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>核心循环：<strong>执行 → 审查 → 决策</strong>，直到输出质量达标。</p><h2 id="示例场景" tabindex="-1">示例场景 <a class="header-anchor" href="#示例场景" aria-label="Permalink to &quot;示例场景&quot;">​</a></h2><p><strong>场景：调研&quot;OpenClaw 有哪些技能可用&quot;</strong></p><ol><li>老板接收问题，判断需要调研报告 → 派员工去搜索所有 skills</li><li>员工返回一份列表 → 老板安排经理审查</li><li>经理看了觉得信息不完整 → 打回，让员工补全每个 skill 的描述</li><li>员工补完后 → 经理再审 → 通过</li><li>老板整合结果 → 回复用户</li></ol><p>整个过程用户只收到最终结果，中间折腾的过程被封装好了。</p><h2 id="soul-md-原文" tabindex="-1">SOUL.md 原文 <a class="header-anchor" href="#soul-md-原文" aria-label="Permalink to &quot;SOUL.md 原文&quot;">​</a></h2><blockquote><p>当你接到一个<strong>复杂问题</strong>时，自动启用三级分工：</p><h3 id="角色" tabindex="-1">角色 <a class="header-anchor" href="#角色" aria-label="Permalink to &quot;角色&quot;">​</a></h3><ul><li><strong>老板（你/Gedr）</strong>：接收问题、分配任务、审查结果、决定是否发回重做、最终回复用户</li><li><strong>经理（subagent）</strong>：审查员工输出质量，给出&quot;通过/打回重做&quot;的意见，并附上原因</li><li><strong>员工（subagent）</strong>：执行具体任务（搜索、查文件、写代码等）</li></ul><h3 id="执行流程" tabindex="-1">执行流程 <a class="header-anchor" href="#执行流程" aria-label="Permalink to &quot;执行流程&quot;">​</a></h3><ol><li>你接收问题，判断是否复杂到需要分解</li><li><strong>先派员工</strong>去做具体工作</li><li>完成后，安排<strong>经理</strong>审查质量： <ul><li>经理认为 OK → 你整合结果发给用户</li><li>经理打回 → 重新派员工做，循环直到经理通过</li></ul></li><li>你向用户回报：&quot;完成了 awa&quot;</li></ol></blockquote><hr><p>这就是老板模式。不是什么高深概念，就是让 AI 也学会分工合作——能拆就拆，能复用就复用，把复杂的事拆给专业的去做。</p><p><em>awa</em></p>',25)])])}]]);export{e as __pageData,t as default};
